import React, { createContext, useContext, useState, useEffect, useRef, useCallback } from 'react';
import { ApiKeyProfile } from '../types';
import { MY_FIXED_KEYS } from '../constants';

interface KeyPoolContextType {
    apiKeys: ApiKeyProfile[];
    activeKeyId: string;
    isCheckingKey: boolean; // Kept for interface compatibility but always false
    addKey: (key: string, label?: string) => Promise<string>;
    deleteKey: (id: string) => void;
    refreshKeyStatus: (id: string) => Promise<void>; // Deprecated placeholder
    checkAllKeys: () => Promise<void>; // Deprecated placeholder
    getActiveKey: () => ApiKeyProfile | undefined;
    isAutoCheckEnabled: boolean;
    toggleAutoCheck: (enabled: boolean) => void;
    setActiveKeyId: (id: string) => void;
}

const KeyPoolContext = createContext<KeyPoolContextType | undefined>(undefined);

export const KeyPoolProvider = ({ children }: React.PropsWithChildren<{}>) => {
    const [apiKeys, setApiKeys] = useState<ApiKeyProfile[]>([]);
    const [activeKeyId, setActiveKeyId] = useState<string>("");

    // Legacy support refs
    const apiKeysRef = useRef<ApiKeyProfile[]>([]);
    useEffect(() => { apiKeysRef.current = apiKeys; }, [apiKeys]);

    // Initial Load
    useEffect(() => {
        try {
            const stored = localStorage.getItem("iso_api_keys");
            const loadedKeys: ApiKeyProfile[] = stored ? JSON.parse(stored) : [];
            const existingKeySet = new Set(loadedKeys.map(k => k.key));
            let hasChanges = false;

            // Inject Environment Keys if not present
            MY_FIXED_KEYS.forEach((fixedKey, index) => {
                if (fixedKey && !existingKeySet.has(fixedKey)) {
                    loadedKeys.push({ 
                        id: `env_key_${index}`, 
                        label: `Default Key ${index + 1}`, 
                        key: fixedKey, 
                        status: 'valid', // Assume valid
                        latency: 0, 
                        lastChecked: new Date().toISOString() 
                    });
                    hasChanges = true;
                }
            });

            // MIGRATION FIX: Update old keys stuck on broken 1.5-flash
            loadedKeys.forEach(k => {
                if (k.activeModel === 'gemini-1.5-flash') {
                    k.activeModel = 'gemini-2.0-flash-exp';
                    hasChanges = true;
                }
            });

            setApiKeys(loadedKeys);
            if(hasChanges) localStorage.setItem("iso_api_keys", JSON.stringify(loadedKeys));

            const savedActiveId = localStorage.getItem("iso_active_key_id");
            if (savedActiveId && loadedKeys.some(k => k.id === savedActiveId)) {
                setActiveKeyId(savedActiveId);
            } else if (loadedKeys.length > 0) {
                setActiveKeyId(loadedKeys[0].id);
            }
        } catch (e) { console.error("Key Load Error", e); }
    }, []);

    // Simplified Add Key - No Validation
    const addKey = async (key: string, label?: string): Promise<string> => {
        if (!key.trim()) return 'empty';
        if (apiKeys.some(k => k.key === key.trim())) return 'duplicate';

        const newProfile: ApiKeyProfile = {
            id: Date.now().toString(),
            label: label || `Key ${apiKeys.length + 1}`,
            key: key.trim(),
            status: 'valid', // Always assume valid
            activeModel: 'gemini-2.0-flash-exp', // CHANGED: Default to safer model
            latency: 0,
            lastChecked: new Date().toISOString()
        };

        const newKeys = [...apiKeys, newProfile];
        setApiKeys(newKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(newKeys));

        // Auto select if first key
        if (apiKeys.length === 0) {
            setActiveKeyId(newProfile.id);
            localStorage.setItem("iso_active_key_id", newProfile.id);
        }

        return 'valid';
    };

    const deleteKey = (id: string) => {
        const newKeys = apiKeys.filter(k => k.id !== id);
        setApiKeys(newKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(newKeys));

        if (activeKeyId === id) {
            const next = newKeys[0];
            const nextId = next ? next.id : "";
            setActiveKeyId(nextId);
            if(nextId) localStorage.setItem("iso_active_key_id", nextId);
            else localStorage.removeItem("iso_active_key_id");
        }
    };

    // Placeholder functions to maintain interface compatibility without logic
    const refreshKeyStatus = async () => {}; 
    const checkAllKeys = async () => {};
    const toggleAutoCheck = () => {};

    const getActiveKey = useCallback(() => apiKeys.find(k => k.id === activeKeyId), [apiKeys, activeKeyId]);

    return (
        <KeyPoolContext.Provider value={{
            apiKeys, activeKeyId, isCheckingKey: false, addKey, deleteKey, refreshKeyStatus,
            checkAllKeys, getActiveKey, isAutoCheckEnabled: false, toggleAutoCheck, setActiveKeyId
        }}>
            {children}
        </KeyPoolContext.Provider>
    );
};

export const useKeyPool = () => {
    const context = useContext(KeyPoolContext);
    if (!context) throw new Error("useKeyPool must be used within KeyPoolProvider");
    return context;
};

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { DEFAULT_GEMINI_MODEL, DEFAULT_VISION_MODEL, MY_FIXED_KEYS } from "../constants";
import { PromptRegistry } from "./promptRegistry";
import { VectorStore } from "./vectorStore";
import { PrivacyService } from "./privacyService"; 
import { LocalIntelligence } from "./localIntelligence";
import { AnalysisResult } from "../types";

// --- CLIENT FACTORY ---
const getAiClient = (overrideKey?: string) => {
    let keyToUse = overrideKey;
    if (!keyToUse && MY_FIXED_KEYS.length > 0) keyToUse = MY_FIXED_KEYS[0];

    // Attempt to grab from Env
    if (!keyToUse) {
        try {
            // @ts-ignore
            if (typeof import.meta !== 'undefined' && import.meta.env && import.meta.env.VITE_API_KEY) {
                // @ts-ignore
                keyToUse = import.meta.env.VITE_API_KEY;
            }
        } catch (e) {}
    }
    if (!keyToUse && typeof process !== 'undefined' && process.env) keyToUse = process.env.API_KEY;

    // Attempt to grab from LocalStorage Pool
    if (!keyToUse) {
        try {
            const poolRaw = localStorage.getItem("iso_api_keys");
            const activeId = localStorage.getItem("iso_active_key_id");
            if (poolRaw) {
                const pool = JSON.parse(poolRaw);
                if (Array.isArray(pool) && pool.length > 0) {
                    const activeKey = pool.find((k: any) => k.id === activeId);
                    keyToUse = activeKey ? activeKey.key : pool[0].key;
                }
            }
        } catch (e) {}
    }

    const apiKey = (keyToUse || "").trim();
    if (!apiKey) return null;
    return new GoogleGenAI({ apiKey });
};

// --- CORE UTILS ---
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * WATERFALL EXECUTION STRATEGY
 * Tries a list of models in sequence. If one fails with a recoverable error (429, 404, 503),
 * it moves to the next.
 */
const executeWithModelCascade = async (
    preferredModel: string,
    operationName: string,
    executeFn: (model: string) => Promise<GenerateContentResponse>
): Promise<string> => {
    // FALLBACK CHAIN:
    // 1. User Preferred (usually Pro 3.0)
    // 2. Flash 2.0 Exp (Fast, New)
    // 3. Flash 1.5 (Stable, High Quota) -> The Safety Net
    // 4. Pro 1.5 (Legacy High Quality)
    const modelChain = [
        preferredModel,
        "gemini-2.0-flash-exp",
        "gemini-1.5-flash",
        "gemini-1.5-pro"
    ];

    // Remove duplicates
    const uniqueModels = [...new Set(modelChain)].filter(m => m);
    let lastError: any = null;

    for (const model of uniqueModels) {
        try {
            console.log(`[${operationName}] Attempting with model: ${model}...`);
            const result = await executeFn(model);
            if (result && result.text) {
                return result.text;
            }
        } catch (error: any) {
            lastError = error;
            const msg = (error.message || "").toLowerCase();
            const status = error.status || error.code || 0;

            console.warn(`[${operationName}] Failed on ${model}: ${msg}`);

            // If it's a "Quota" (429) or "Not Found" (404) or "Overloaded" (503), we try the next one.
            // If it's "Invalid Key" (403), we stop immediately (no point switching models).
            if (status === 403 || msg.includes("key not valid") || msg.includes("api_key_invalid")) {
                throw new Error("Invalid API Key. Please check your settings.");
            }

            // Short pause before switching to be polite to the network
            await wait(500); 
        }
    }

    throw new Error(`All AI models failed. Last error: ${lastError?.message || 'Unknown'}`);
};

export const validateApiKey = async (rawKey: string): Promise<{ isValid: boolean, latency: number, errorType?: string, errorMessage?: string, activeModel?: string }> => {
    const key = rawKey ? rawKey.trim().replace(/^["']|["']$/g, '') : "";
    if (!key) return { isValid: false, latency: 0, errorType: 'invalid', errorMessage: "Key is empty" };

    const ai = new GoogleGenAI({ apiKey: key });

    // Validation: Try the most robust model first (1.5 Flash)
    // If 1.5 Flash works, the key is good.
    const modelsToProbe = ["gemini-1.5-flash", "gemini-2.0-flash-exp"];

    for (const model of modelsToProbe) {
        const start = performance.now();
        try {
            await ai.models.generateContent({ model, contents: { parts: [{ text: "Hi" }] } });
            return { isValid: true, latency: Math.round(performance.now() - start), activeModel: model };
        } catch (error: any) {
            const msg = (error.message || "").toLowerCase();
            if (msg.includes("key") || error.status === 403) {
                return { isValid: false, latency: 0, errorType: 'invalid', errorMessage: "Invalid API Key." };
            }
            // If quota/404, loop to next model
        }
    }

    // If we get here, assuming valid but maybe quota issues, return valid to let app try
    return { isValid: true, latency: 999, activeModel: "gemini-1.5-flash" }; 
};

