        else if (modelRaw.includes("1.5-flash")) modelDisplay = "FLASH 1.5";
        else if (modelRaw.includes("3-pro")) modelDisplay = "PRO 3.0";
        else if (modelRaw.includes("1.5-pro")) modelDisplay = "PRO 1.5";

